### Inject TypeORM DataSource in NestJS module

Source: https://github.com/nestjs/docs.nestjs.com/blob/master/content/techniques/sql.md

Inject the TypeORM DataSource object into a NestJS module constructor for database operations. The DataSource becomes available application-wide after TypeOrmModule.forRoot() configuration and can be injected without additional module imports.

```typescript
import { DataSource } from 'typeorm';

@Module({
  imports: [TypeOrmModule.forRoot(), UsersModule],
})
export class AppModule {
  constructor(private dataSource: DataSource) {}
}
```

```typescript
import { DataSource } from 'typeorm';

@Dependencies(DataSource)
@Module({
  imports: [TypeOrmModule.forRoot(), UsersModule],
})
export class AppModule {
  constructor(dataSource) {
    this.dataSource = dataSource;
  }
}
```

--------------------------------

### Install NestJS Schedule Package

Source: https://github.com/nestjs/docs.nestjs.com/blob/master/content/techniques/task-scheduling.md

Install the @nestjs/schedule package as a dependency in your NestJS project. This package provides task scheduling capabilities and integrates with the node-cron library for cron-like functionality.

```bash
npm install --save @nestjs/schedule
```

--------------------------------

### Implementing a GraphQL-Compatible Local AuthGuard in NestJS

Source: https://github.com/nestjs/docs.nestjs.com/blob/master/content/recipes/passport.md

This `GqlLocalAuthGuard` extends the standard `AuthGuard('local')` for GraphQL environments. It overrides `getRequest()` to merge GraphQL arguments into the request body, ensuring that Passport's local strategy can access the necessary credentials for validation.

```typescript
@Injectable()
export class GqlLocalAuthGuard extends AuthGuard('local') {
  getRequest(context: ExecutionContext) {
    const gqlExecutionContext = GqlExecutionContext.create(context);
    const gqlContext = gqlExecutionContext.getContext();
    const gqlArgs = gqlExecutionContext.getArgs();

    gqlContext.req.body = { ...gqlContext.req.body, ...gqlArgs };
    return gqlContext.req;
  }
}
```

--------------------------------

### Implement a Basic Logging Interceptor in NestJS

Source: https://github.com/nestjs/docs.nestjs.com/blob/master/content/interceptors.md

This interceptor demonstrates aspect interception in NestJS to log user interaction. It logs a 'Before...' message before handling a request and an 'After...' message with the elapsed time after the request completes, using RxJS `tap` operator. It can be used for tasks like performance monitoring or event dispatching.

```typescript
import { Injectable, NestInterceptor, ExecutionContext, CallHandler } from '@nestjs/common';
import { Observable } from 'rxjs';
import { tap } from 'rxjs/operators';

@Injectable()
export class LoggingInterceptor implements NestInterceptor {
  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    console.log('Before...');

    const now = Date.now();
    return next
      .handle()
      .pipe(
        tap(() => console.log(`After... ${Date.now() - now}ms`)),
      );
  }
}
```

```typescript
import { Injectable } from '@nestjs/common';
import { Observable } from 'rxjs';
import { tap } from 'rxjs/operators';

@Injectable()
export class LoggingInterceptor {
  intercept(context, next) {
    console.log('Before...');

    const now = Date.now();
    return next
      .handle()
      .pipe(
        tap(() => console.log(`After... ${Date.now() - now}ms`)),
      );
  }
}
```

--------------------------------

### Implement RolesGuard in NestJS

Source: https://github.com/nestjs/docs.nestjs.com/blob/master/content/security/authorization.md

Creates a guard that implements CanActivate to validate user roles against required route permissions. Uses the Reflector utility to retrieve role metadata from route handlers and compares them with the current user's roles from the request object.

```typescript
import { Injectable, CanActivate, ExecutionContext } from '@nestjs/common';
import { Reflector } from '@nestjs/core';

@Injectable()
export class RolesGuard implements CanActivate {
  constructor(private reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    const requiredRoles = this.reflector.getAllAndOverride<Role[]>(ROLES_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);
    if (!requiredRoles) {
      return true;
    }
    const { user } = context.switchToHttp().getRequest();
    return requiredRoles.some((role) => user.roles?.includes(role));
  }
}
```

```javascript
import { Injectable, Dependencies } from '@nestjs/common';
import { Reflector } from '@nestjs/core';

@Injectable()
@Dependencies(Reflector)
export class RolesGuard {
  constructor(reflector) {
    this.reflector = reflector;
  }

  canActivate(context) {
    const requiredRoles = this.reflector.getAllAndOverride(ROLES_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);
    if (!requiredRoles) {
      return true;
    }
    const { user } = context.switchToHttp().getRequest();
    return requiredRoles.some((role) => user.roles.includes(role));
  }
}
```

