    `, [now.toISOString(), yearEnd.toISOString()]);

    // eslint-disable-next-line no-console
    console.log('Seed complete.');
  } finally {
    await queryRunner.release();
    await AppDataSource.destroy();
  }
}

seed().catch((err) => {
  // eslint-disable-next-line no-console
  console.error('Seed failed:', err);
  process.exit(1);
});

