import { useEffect, useState } from 'react';
import { riskApi } from '@/api/risk.api';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { DataTable } from '@/components/common/DataTable';
import { StatusBadge } from '@/components/common/StatusBadge';
import { Badge } from '@/components/ui/badge';
import { formatDateTime } from '@/lib/utils';
import type { RiskEventDto, IncidentTicketDto } from '@checc/shared/types/risk.types';
import { Shield, AlertTriangle, FileWarning } from 'lucide-react';

export function RiskDashboardPage() {
  const [events, setEvents] = useState<RiskEventDto[]>([]);
  const [incidents, setIncidents] = useState<IncidentTicketDto[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      riskApi.listRiskEvents(1, 10),
      riskApi.listIncidents(1, 10),
    ]).then(([eventsRes, incidentsRes]) => {
      setEvents(eventsRes.data.data);
      setIncidents(incidentsRes.data.data);
      setIsLoading(false);
    }).catch(() => setIsLoading(false));
  }, []);

  const severityColors: Record<string, 'secondary' | 'warning' | 'destructive' | 'default'> = {
    low: 'secondary',
    medium: 'warning',
    high: 'destructive',
    critical: 'destructive',
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Risk Dashboard</h1>
        <p className="text-muted-foreground">Monitor security events and incidents</p>
      </div>

      <div className="grid gap-4 md:grid-cols-3">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Open Incidents</CardTitle>
            <AlertTriangle className="h-4 w-4 text-destructive" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {incidents.filter((i) => i.status === 'OPEN').length}
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Recent Events</CardTitle>
            <Shield className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{events.length}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Critical</CardTitle>
            <FileWarning className="h-4 w-4 text-destructive" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {events.filter((e) => e.severity === 'critical').length}
            </div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Recent Risk Events</CardTitle>
        </CardHeader>
        <CardContent>
          <DataTable
            columns={[
              { header: 'Time', accessor: (row) => formatDateTime(row.detectedAt) },
              { header: 'Type', accessor: (row) => row.eventType.replace('_', ' ') },
              {
                header: 'Severity',
                accessor: (row) => (
                  <Badge variant={severityColors[row.severity] || 'default'}>
                    {row.severity.toUpperCase()}
                  </Badge>
                ),
              },
              { header: 'IP', accessor: (row) => row.ipAddress || '—' },
            ]}
            data={events}
            isLoading={isLoading}
            emptyMessage="No risk events detected"
          />
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Incident Tickets</CardTitle>
        </CardHeader>
        <CardContent>
          <DataTable
            columns={[
              { header: 'Title', accessor: 'title' as keyof IncidentTicketDto },
              { header: 'Status', accessor: (row) => <StatusBadge status={row.status} /> },
              { header: 'Created', accessor: (row) => formatDateTime(row.createdAt) },
            ]}
            data={incidents}
            isLoading={isLoading}
            emptyMessage="No incidents"
          />
        </CardContent>
      </Card>
    </div>
  );
}

